fn solve(value: Vec<i64>, limit: Vec<i64>) -> i64 {
    let n = value.len();
    let mut elements = (0..n).collect::<Vec<_>>();
    elements.sort_by(|&i, &j| value[j].cmp(&value[i]));

    let mut max_heap = std::collections::BinaryHeap::new();
    let mut active_count = 0;
    let mut total_sum = 0;
    let mut active = vec![true; n];

    for &i in &elements {
        if active[i] && active_count < limit[i] {
            total_sum += value[i];
            active[i] = false;
            active_count += 1;
            max_heap.push(value[i]);

            // Keep the heap size manageable by removing the smallest value
            // (we only need to keep track of the largest values)
            while max_heap.len() > limit[i] as usize {
                max_heap.pop();
            }
        }
    }

    total_sum
}
